
'use server';

import { sendMail } from '@/lib/email';
import PDFDocument from 'pdfkit';
import { format } from 'date-fns';

/**
 * @fileOverview Server action to generate a clean, simple transaction report PDF and email it to the user.
 */

export async function exportTransactionsToPdf(
  email: string,
  transactions: any[],
  startDate: string,
  endDate: string,
  currencySymbol: string
) {
  try {
    const doc = new PDFDocument({
      margin: 40,
      size: 'A4'
    });
    const chunks: Buffer[] = [];

    doc.on('data', (chunk) => chunks.push(chunk));

    // Simple Header
    doc
      .fontSize(24)
      .font('Helvetica-Bold')
      .fillColor('#1e293b')
      .text('Wallet Tally', 40, 40);

    doc
      .fontSize(10)
      .font('Helvetica')
      .fillColor('#64748b')
      .text('Transaction Report', 40, 70);

    // Horizontal line
    doc
      .strokeColor('#cbd5e1')
      .lineWidth(1)
      .moveTo(40, 90)
      .lineTo(555, 90)
      .stroke();

    // Report Period
    doc
      .fontSize(9)
      .font('Helvetica')
      .fillColor('#475569')
      .text(`Period: ${format(new Date(startDate), 'MMM dd, yyyy')} - ${format(new Date(endDate), 'MMM dd, yyyy')}`, 40, 105)
      .text(`Generated: ${format(new Date(), 'MMM dd, yyyy')}`, 40, 120);

    // Calculate totals
    const totalIncome = transactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + (t.amount || 0), 0);

    const totalExpense = transactions
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + (t.amount || 0), 0);

    const netBalance = totalIncome - totalExpense;

    // Summary Box
    const summaryY = 145;
    doc
      .rect(40, summaryY, 515, 60)
      .fillAndStroke('#f8fafc', '#e2e8f0');

    doc
      .fontSize(8)
      .font('Helvetica-Bold')
      .fillColor('#64748b')
      .text('TOTAL INCOME', 60, summaryY + 15)
      .text('TOTAL EXPENSE', 230, summaryY + 15)
      .text('NET BALANCE', 400, summaryY + 15);

    doc
      .fontSize(14)
      .font('Helvetica-Bold')
      .fillColor('#10b981')
      .text(`${currencySymbol}${totalIncome.toFixed(2)}`, 60, summaryY + 32)
      .fillColor('#ef4444')
      .text(`${currencySymbol}${totalExpense.toFixed(2)}`, 230, summaryY + 32)
      .fillColor(netBalance >= 0 ? '#10b981' : '#ef4444')
      .text(`${currencySymbol}${netBalance.toFixed(2)}`, 400, summaryY + 32);

    // Table Header
    const tableTop = 230;
    doc
      .fontSize(8)
      .font('Helvetica-Bold')
      .fillColor('#64748b')
      .text('DATE', 40, tableTop)
      .text('TYPE', 110, tableTop)
      .text('CATEGORY', 170, tableTop)
      .text('DESCRIPTION', 270, tableTop)
      .text('AMOUNT', 480, tableTop, { align: 'right', width: 75 });

    // Table header line
    doc
      .strokeColor('#cbd5e1')
      .lineWidth(0.5)
      .moveTo(40, tableTop + 15)
      .lineTo(555, tableTop + 15)
      .stroke();

    // Table Rows
    let currentY = tableTop + 25;
    const rowHeight = 20;
    const pageHeight = 750;

    transactions.forEach((t, index) => {
      // Check for page overflow
      if (currentY > pageHeight) {
        doc.addPage();
        currentY = 50;

        // Repeat header on new page
        doc
          .fontSize(8)
          .font('Helvetica-Bold')
          .fillColor('#64748b')
          .text('DATE', 40, currentY)
          .text('TYPE', 110, currentY)
          .text('CATEGORY', 170, currentY)
          .text('DESCRIPTION', 270, currentY)
          .text('AMOUNT', 480, currentY, { align: 'right', width: 75 });

        doc
          .strokeColor('#cbd5e1')
          .lineWidth(0.5)
          .moveTo(40, currentY + 15)
          .lineTo(555, currentY + 15)
          .stroke();

        currentY += 25;
      }

      // Alternate row background
      if (index % 2 === 0) {
        doc
          .rect(40, currentY - 5, 515, rowHeight)
          .fill('#fafafa');
      }

      // Row data
      const dateStr = t.date ? format(new Date(t.date), 'MM/dd/yyyy') : 'N/A';
      const typeStr = t.type ? t.type.charAt(0).toUpperCase() + t.type.slice(1) : '-';
      const categoryStr = t.category || '-';
      const descStr = t.description || '-';
      const amountStr = `${t.type === 'income' ? '+' : '-'}${currencySymbol}${Number(t.amount || 0).toFixed(2)}`;

      doc
        .fontSize(8)
        .font('Helvetica')
        .fillColor('#334155')
        .text(dateStr, 40, currentY)
        .text(typeStr, 110, currentY)
        .text(categoryStr, 170, currentY, { width: 90, ellipsis: true })
        .text(descStr, 270, currentY, { width: 200, ellipsis: true })
        .fillColor(t.type === 'income' ? '#10b981' : '#ef4444')
        .font('Helvetica-Bold')
        .text(amountStr, 480, currentY, { align: 'right', width: 75 });

      currentY += rowHeight;
    });

    // Footer
    const footerY = doc.page.height - 40;
    doc
      .fontSize(7)
      .font('Helvetica')
      .fillColor('#94a3b8')
      .text(
        `Wallet Tally - Personal Finance Management | Page 1 of 1`,
        40,
        footerY,
        { align: 'center', width: 515 }
      );

    doc.end();

    const pdfBuffer = await new Promise<Buffer>((resolve) => {
      doc.on('end', () => {
        resolve(Buffer.concat(chunks));
      });
    });

    await sendMail({
      to: email,
      subject: `Wallet Tally Transaction Report: ${format(new Date(startDate), 'MMM dd, yyyy')} - ${format(new Date(endDate), 'MMM dd, yyyy')}`,
      text: `Please find attached your Wallet Tally transaction report for the period ${format(new Date(startDate), 'MMM dd, yyyy')} to ${format(new Date(endDate), 'MMM dd, yyyy')}.`,
      html: `
        <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 600px; margin: 0 auto; padding: 40px 20px;">
          <div style="text-align: center; margin-bottom: 30px;">
            <h1 style="color: #1e293b; font-size: 24px; margin: 0 0 8px 0;">Wallet Tally</h1>
            <p style="color: #64748b; font-size: 14px; margin: 0;">Transaction Report Ready</p>
          </div>
          
          <div style="background: #ffffff; border: 1px solid #e2e8f0; border-radius: 8px; padding: 30px; margin-bottom: 20px;">
            <p style="color: #334155; font-size: 15px; line-height: 1.6; margin: 0 0 20px 0;">
              Your transaction report has been generated and is attached to this email.
            </p>
            
            <div style="background: #f8fafc; border-left: 3px solid #3b82f6; padding: 15px; margin: 20px 0;">
              <p style="color: #64748b; font-size: 12px; font-weight: 600; margin: 0 0 8px 0; text-transform: uppercase; letter-spacing: 0.5px;">Report Period</p>
              <p style="color: #1e293b; font-size: 14px; margin: 0;">${format(new Date(startDate), 'MMMM dd, yyyy')} - ${format(new Date(endDate), 'MMMM dd, yyyy')}</p>
            </div>
            
            <div style="margin-top: 20px; padding-top: 20px; border-top: 1px solid #e2e8f0;">
              <p style="color: #64748b; font-size: 13px; margin: 0;">
                <strong>Total Income:</strong> ${currencySymbol}${totalIncome.toFixed(2)}<br>
                <strong>Total Expense:</strong> ${currencySymbol}${totalExpense.toFixed(2)}<br>
                <strong>Net Balance:</strong> ${currencySymbol}${netBalance.toFixed(2)}
              </p>
            </div>
          </div>
          
          <div style="text-align: center; padding-top: 20px; border-top: 1px solid #e2e8f0;">
            <p style="color: #94a3b8; font-size: 12px; margin: 0;">
              This is an automated email from Wallet Tally<br>
              Please do not reply to this message
            </p>
          </div>
        </div>
      `,
      attachments: [
        {
          filename: `WalletTally_Report_${format(new Date(startDate), 'yyyy-MM-dd')}_${format(new Date(endDate), 'yyyy-MM-dd')}.pdf`,
          content: pdfBuffer,
        },
      ],
    });

    return { success: true };
  } catch (error: any) {
    console.error('PDF Export Error:', error);
    return { success: false, error: error.message };
  }
}
